# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharehandler

import android.content.ClipData
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Patterns
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleShareIntent(intent)
        finish()
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        setIntent(intent)
        handleShareIntent(intent)
        finish()
    }

    private fun handleShareIntent(intent: Intent?) {
        if (intent == null) return

        when (intent.action) {
            Intent.ACTION_SEND -> handleSend(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleSendMultiple(intent)
        }
    }

    private fun handleSend(intent: Intent) {
        val type = intent.type.orEmpty()

        when {
            type.startsWith("text/") -> {
                val text = intent.getStringExtra(Intent.EXTRA_TEXT)
                val url = extractFirstUrl(text)
                if (url != null) {
                    processSharedUrl(url)
                } else if (!text.isNullOrBlank()) {
                    processSharedText(text)
                }
            }

            type.startsWith("image/") -> {
                val imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
                    ?: extractFirstUriFromClipData(intent.clipData)
                if (imageUri != null) {
                    processSharedImage(imageUri)
                }
            }

            else -> {
                val text = intent.getStringExtra(Intent.EXTRA_TEXT)
                val url = extractFirstUrl(text)
                if (url != null) {
                    processSharedUrl(url)
                    return
                }

                val streamUri = intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
                    ?: extractFirstUriFromClipData(intent.clipData)
                if (streamUri != null) {
                    processSharedImage(streamUri)
                    return
                }

                if (!text.isNullOrBlank()) {
                    processSharedText(text)
                }
            }
        }
    }

    private fun handleSendMultiple(intent: Intent) {
        val type = intent.type.orEmpty()
        val uris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
            ?.filterNotNull()
            .orEmpty()
            .ifEmpty { extractUrisFromClipData(intent.clipData) }

        if (type.startsWith("image/") || uris.isNotEmpty()) {
            uris.forEach { processSharedImage(it) }
            return
        }

        val text = intent.getStringExtra(Intent.EXTRA_TEXT)
        val url = extractFirstUrl(text)
        if (url != null) {
            processSharedUrl(url)
        } else if (!text.isNullOrBlank()) {
            processSharedText(text)
        }
    }

    private fun extractFirstUrl(text: String?): String? {
        if (text.isNullOrBlank()) return null
        val matcher = Patterns.WEB_URL.matcher(text)
        return if (matcher.find()) matcher.group() else null
    }

    private fun extractFirstUriFromClipData(clipData: ClipData?): Uri? {
        if (clipData == null || clipData.itemCount == 0) return null
        for (i in 0 until clipData.itemCount) {
            val uri = clipData.getItemAt(i).uri
            if (uri != null) return uri
        }
        return null
    }

    private fun extractUrisFromClipData(clipData: ClipData?): List<Uri> {
        if (clipData == null || clipData.itemCount == 0) return emptyList()
        val result = ArrayList<Uri>(clipData.itemCount)
        for (i in 0 until clipData.itemCount) {
            val uri = clipData.getItemAt(i).uri
            if (uri != null) result.add(uri)
        }
        return result
    }

    private fun processSharedUrl(url: String) {
        android.util.Log.d("ShareReceiverActivity", "Shared URL: $url")
    }

    private fun processSharedText(text: String) {
        android.util.Log.d("ShareReceiverActivity", "Shared Text: $text")
    }

    private fun processSharedImage(imageUri: Uri) {
        contentResolver.takePersistableUriPermissionIfPossible(imageUri, Intent.FLAG_GRANT_READ_URI_PERMISSION)
        android.util.Log.d("ShareReceiverActivity", "Shared Image URI: $imageUri")
    }

    private fun android.content.ContentResolver.takePersistableUriPermissionIfPossible(
        uri: Uri,
        flags: Int
    ) {
        try {
            takePersistableUriPermission(uri, flags)
        } catch (_: SecurityException) {
        } catch (_: UnsupportedOperationException) {
        }
    }
}

